import React, { useState, useEffect } from 'react';
import { Shield, AlertTriangle, Wifi, Battery, Zap, User, CheckCircle, ArrowRight, Star, XCircle, Loader2 } from 'lucide-react';

// --- CONFIGURAÇÕES VISUAIS ---
const LOGO_URL = "https://i.ibb.co/ymRw3mjX/kedu-logo-new.png"; 
const PILOT_1_URL = "https://i.ibb.co/pvry1Mv3/comandante1.png";
const PILOT_2_URL = "https://i.ibb.co/cS3kNj0p/comandante2.png";

// --- CUSTOM ASSETS (SVG) ---
const RealisticRocket = ({ className = "", size = 200 }) => (
  <svg 
    width={size} 
    height={size * 1.5} 
    viewBox="0 0 100 150" 
    fill="none" 
    xmlns="http://www.w3.org/2000/svg" 
    className={className}
  >
    <defs>
      <radialGradient id="flameGradient" cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
        <stop offset="0%" stopColor="#fbbf24" />
        <stop offset="50%" stopColor="#f59e0b" />
        <stop offset="100%" stopColor="transparent" />
      </radialGradient>
    </defs>
    <ellipse cx="50" cy="75" rx="12" ry="60" fill="black" fillOpacity="0.2" />
    <path d="M38 110 L25 135 L40 130 Z" fill="#475569" stroke="#1e293b" strokeWidth="1"/>
    <path d="M62 110 L75 135 L60 130 Z" fill="#475569" stroke="#1e293b" strokeWidth="1"/>
    <path d="M50 15 C62 45 62 110 62 125 L38 125 C38 110 38 45 50 15Z" fill="#f8fafc" stroke="#cbd5e1" strokeWidth="1" />
    <path d="M50 15 C58 35 58 50 58 50 L42 50 C42 50 42 35 50 15Z" fill="#e2e8f0" />
    <line x1="38" y1="70" x2="62" y2="70" stroke="#cbd5e1" strokeWidth="0.5" />
    <line x1="38" y1="95" x2="62" y2="95" stroke="#cbd5e1" strokeWidth="0.5" />
    <circle cx="50" cy="60" r="3" fill="#38bdf8" stroke="#0ea5e9" strokeWidth="1" />
    <circle cx="50" cy="80" r="3" fill="#38bdf8" stroke="#0ea5e9" strokeWidth="1" />
    <path d="M42 125 L40 132 L60 132 L58 125 Z" fill="#334155" />
    <text x="46" y="110" fontSize="4" fill="#94a3b8" fontWeight="bold">KEDU</text>
  </svg>
);

const SpaceBackground = () => (
  <div className="absolute inset-0 z-0 overflow-hidden bg-slate-950">
    <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-indigo-900 via-[#0B0B1E] to-black opacity-80"></div>
    {[...Array(30)].map((_, i) => (
      <div 
        key={i}
        className="absolute rounded-full bg-white animate-pulse"
        style={{
          width: Math.random() * 3 + 1 + 'px',
          height: Math.random() * 3 + 1 + 'px',
          top: Math.random() * 100 + '%',
          left: Math.random() * 100 + '%',
          opacity: Math.random() * 0.7 + 0.3,
          animationDuration: Math.random() * 3 + 2 + 's'
        }}
      />
    ))}
    <div className="absolute top-0 left-0 w-full h-1/2 bg-purple-600/10 blur-[100px] rounded-full mix-blend-screen"></div>
    <div className="absolute bottom-0 right-0 w-full h-1/2 bg-blue-600/10 blur-[100px] rounded-full mix-blend-screen"></div>
  </div>
);

const ActionButton = ({ onClick, children, variant = 'primary', className = '' }) => {
  const baseStyles = "w-full min-h-[160px] text-3xl font-black uppercase tracking-widest rounded-3xl transition-all duration-200 active:scale-95 flex items-center justify-center text-center px-10 shadow-xl relative overflow-hidden group";

  const variants = {
    primary: "bg-gradient-to-r from-blue-600 to-indigo-700 border-4 border-blue-400/30 text-white shadow-[0_0_40px_rgba(59,130,246,0.4)] hover:shadow-[0_0_60px_rgba(59,130,246,0.7)]",
    alert: "bg-gradient-to-r from-red-600 to-orange-700 border-4 border-red-400/30 text-white shadow-[0_0_40px_rgba(220,38,38,0.4)] animate-pulse",
    neutral: "bg-slate-800/80 backdrop-blur-md border-4 border-slate-600 text-slate-200 hover:bg-slate-700",
    success: "bg-gradient-to-r from-emerald-600 to-teal-700 border-4 border-emerald-400/30 text-white shadow-[0_0_40px_rgba(16,185,129,0.4)]",
  };

  return (
    <button onClick={onClick} className={`${baseStyles} ${variants[variant]} ${className}`}>
      <span className="relative z-10 flex items-center gap-4">{children}</span>
      <div className="absolute top-0 left-0 w-full h-1/2 bg-white/10 z-0"></div>
    </button>
  );
};

const ErrorOverlay = ({ onRetry }) => (
  <div className="fixed inset-0 z-50 bg-red-950/98 flex flex-col items-center justify-center p-12 animate-in fade-in zoom-in duration-300">
    <div className="bg-black/40 p-12 rounded-full mb-12 border-8 border-red-500 animate-bounce">
      <AlertTriangle size={160} className="text-red-500" />
    </div>
    <h2 className="text-7xl font-black text-white mb-8 text-center uppercase tracking-tighter drop-shadow-2xl">Impacto!</h2>
    <p className="text-3xl text-red-100 text-center mb-16 max-w-2xl leading-relaxed">
      Essa decisão pode comprometer o fluxo da missão. <br/>Ajuste a rota, comandante.
    </p>
    <ActionButton onClick={onRetry} variant="primary">
      <Zap className="mr-4" /> Tentar Novamente
    </ActionButton>
  </div>
);

const generateContent = async (prompt) => {
  const apiKey = ""; 
  try {
    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ parts: [{ text: prompt }] }]
        })
      }
    );
    const data = await response.json();
    return data.candidates?.[0]?.content?.parts?.[0]?.text || null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return null;
  }
};

export default function App() {
  const [stage, setStage] = useState(0);
  const [pilot, setPilot] = useState(null);
  const [showError, setShowError] = useState(false);
  const [introText, setIntroText] = useState("Toda escola que cresce precisa enfrentar uma grande missão. Hoje, você assume o comando da sua!");
  const [outroText, setOutroText] = useState("Pilotar a gestão escolar não é simples. Mas com estabilidade e suporte, tudo fica mais leve.");
  const [loadingIntro, setLoadingIntro] = useState(false);

  useEffect(() => {
    const fetchIntro = async () => {
      setLoadingIntro(true);
      const text = await generateContent("Crie uma introdução curta (max 2 frases), épica e inspiradora para um jogo de gestão escolar espacial. Português.");
      if (text) setIntroText(text);
      setLoadingIntro(false);
    };
    fetchIntro();
  }, []);

  useEffect(() => {
    if (stage === 12) {
      const fetchOutro = async () => {
        const text = await generateContent("Crie uma mensagem de 'Missão Cumprida' curta (max 2 frases) para um diretor de escola espacial vitorioso. Português.");
        if (text) setOutroText(text);
      };
      fetchOutro();
    }
  }, [stage]);

  useEffect(() => {
    if (stage === 2) {
      const timer = setTimeout(() => setStage(3), 4000);
      return () => clearTimeout(timer);
    }
  }, [stage]);

  const handleStart = () => setStage(1);
  const handleSelectPilot = (p) => {
    setPilot(p);
    setTimeout(() => setStage(2), 600);
  };
  const handleCorrectAnswer = (nextStageId) => setStage(nextStageId);
  const handleWrongAnswer = () => setShowError(true);
  const closeError = () => setShowError(false);

  // --- COMPONENTES AUXILIARES ---

  const HeaderLogo = () => (
    <div className="absolute top-10 left-1/2 -translate-x-1/2 z-50 animate-in fade-in slide-in-from-top-4 duration-700 w-full flex justify-center px-8">
      <img 
        src={LOGO_URL} 
        alt="Kedu Logo" 
        className="max-h-32 w-auto object-contain drop-shadow-[0_0_20px_rgba(59,130,246,0.3)]" 
        onError={(e) => {
          e.target.src = "https://kedu.com.br/wp-content/uploads/2021/08/logo-kedu-horizontal-azul.png";
        }}
      />
    </div>
  );

  // --- RENDER STAGES ---

  const renderIntro = () => (
    <div className="flex flex-col items-center justify-between h-full py-24 px-12 text-center relative z-10">
      <div className="mt-16 w-full flex flex-col items-center">
        <div className="p-4 mb-10 animate-in zoom-in duration-1000 w-full flex justify-center overflow-visible">
          <img 
            src={LOGO_URL} 
            alt="Kedu Logo" 
            className="max-w-[85%] h-auto object-contain drop-shadow-[0_0_50px_rgba(59,130,246,0.2)]"
            style={{ imageRendering: 'auto' }}
            onError={(e) => {
                e.target.src = "https://kedu.com.br/wp-content/uploads/2021/08/logo-kedu-horizontal-azul.png";
            }}
          />
        </div>
        <h1 className="text-8xl font-black text-white uppercase tracking-tighter mb-4 drop-shadow-[0_0_20px_rgba(255,255,255,0.5)] leading-none">
          Base Espacial<br/><span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">KEDU</span>
        </h1>
      </div>

      <div className="bg-slate-900/70 backdrop-blur-md p-12 rounded-[3rem] border-2 border-slate-700 shadow-2xl min-h-[350px] flex items-center justify-center">
        {loadingIntro ? <Loader2 className="animate-spin text-blue-400" size={80} /> : (
          <p className="text-4xl text-slate-100 font-medium leading-tight animate-in fade-in duration-700">{introText}</p>
        )}
      </div>

      <ActionButton onClick={handleStart} variant="primary">INICIAR MISSÃO</ActionButton>
    </div>
  );

  const renderPilot = () => (
    <div className="flex flex-col items-center h-full py-24 px-12 relative z-10">
      <HeaderLogo />
      <h2 className="text-6xl font-black text-white text-center mb-6 mt-36 uppercase tracking-widest">Escolha o Piloto</h2>
      <p className="text-3xl text-slate-300 text-center mb-16 font-medium">Quem representa você nessa jornada?</p>
      <div className="flex-1 w-full flex flex-col gap-12 justify-center">
        {['male', 'female'].map((p) => (
          <button key={p} onClick={() => handleSelectPilot(p)}
            className={`relative rounded-[3rem] border-4 transition-all duration-300 flex flex-col items-center justify-center p-12 h-[450px]
              ${pilot === p ? 'bg-blue-900/80 border-blue-400 shadow-[0_0_80px_rgba(59,130,246,0.9)] scale-105 z-20' : 'bg-slate-800/40 border-slate-700 opacity-80'}`}
          >
            <div className="w-64 h-64 rounded-full mb-8 overflow-hidden border-4 border-blue-400/30 bg-slate-700 shadow-[0_0_30px_rgba(0,0,0,0.5)]">
              <img 
                src={p === 'male' ? PILOT_1_URL : PILOT_2_URL} 
                alt="Comandante" 
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.target.style.display = 'none';
                }}
              />
              <div className="w-full h-full flex items-center justify-center">
                <User size={120} className="text-white opacity-20" />
              </div>
            </div>
            <span className="text-5xl font-black text-white uppercase tracking-[0.2em]">{p === 'male' ? 'Comandante 1' : 'Comandante 2'}</span>
            {pilot === p && <div className="absolute top-8 right-8 bg-blue-500 rounded-full p-4 animate-bounce"><CheckCircle className="text-white" size={48} /></div>}
          </button>
        ))}
      </div>
      <div className="h-[200px] flex items-center justify-center"><p className="text-slate-400 uppercase tracking-[0.5em] text-xl animate-pulse">Selecione para decolar</p></div>
    </div>
  );

  const renderLaunch = () => (
    <div className="flex flex-col items-center justify-center h-full relative z-10 overflow-hidden">
      <HeaderLogo />
      <div className="absolute inset-0 flex items-end justify-center pb-40 animate-[slideUp_4s_ease-in-out_forwards]">
        <div className="relative flex flex-col items-center">
          <div className="absolute top-[80%] w-32 h-[800px] bg-gradient-to-b from-orange-400 via-orange-600/50 to-transparent blur-[60px] animate-pulse"></div>
          <RealisticRocket size={350} className="drop-shadow-[0_0_50px_rgba(255,255,255,0.5)]" />
        </div>
      </div>
      <div className="absolute top-[35%] w-full text-center px-12">
        <h2 className="text-7xl font-black text-white mb-8 animate-pulse uppercase tracking-widest drop-shadow-2xl leading-none">Decolagem Autorizada</h2>
        <p className="text-4xl text-blue-200 uppercase font-bold tracking-tighter opacity-80">Iniciando protocolo de crescimento...</p>
      </div>
    </div>
  );

  const renderAlert = (icon, title, text, nextStage) => (
    <div className="flex flex-col items-center justify-center h-full py-24 px-12 relative z-10 bg-red-950/40">
      <HeaderLogo />
      <div className="absolute inset-0 bg-red-600/10 animate-pulse z-0"></div>
      <div className="z-10 flex flex-col items-center text-center mt-28">
        <div className="mb-12 relative">
           <div className="absolute inset-0 bg-red-500 blur-[80px] opacity-60 animate-ping"></div>
           {icon}
        </div>
        <h2 className="text-7xl font-black text-red-500 mb-10 uppercase tracking-tighter leading-none">{title}</h2>
        <div className="bg-slate-900/90 border-4 border-red-500/50 p-16 rounded-[3rem] mb-20 shadow-2xl">
          <p className="text-4xl text-white leading-tight font-medium">{text}</p>
        </div>
        <ActionButton onClick={() => setStage(nextStage)} variant="alert">ACESSAR PAINEL</ActionButton>
      </div>
    </div>
  );

  const renderDecision = (question, options, correctIndex, nextSuccessStage) => (
    <div className="flex flex-col h-full py-24 px-12 relative z-10">
      <HeaderLogo />
      <div className="mt-36 mb-16">
        <h2 className="text-4xl font-black text-blue-400 uppercase mb-4 tracking-widest">Painel de Controle</h2>
        <div className="h-3 w-48 bg-blue-500 rounded-full shadow-[0_0_20px_rgba(59,130,246,0.8)]"></div>
      </div>
      <div className="mb-16">
        <h3 className="text-5xl font-black text-white leading-tight drop-shadow-md">{question}</h3>
      </div>
      <div className="flex-1 flex flex-col gap-8 justify-center">
        {options.map((opt, idx) => (
          <button key={idx} onClick={() => idx === correctIndex ? handleCorrectAnswer(nextSuccessStage) : handleWrongAnswer()}
            className="w-full p-12 min-h-[220px] rounded-[2.5rem] bg-slate-800/80 border-4 border-slate-600 hover:border-blue-400 text-left transition-all active:scale-95 group relative overflow-hidden"
          >
            <div className="flex items-start gap-8 relative z-10">
              <div className="mt-2 w-16 h-16 rounded-full border-4 border-slate-500 flex-shrink-0 flex items-center justify-center group-hover:border-blue-400 group-hover:bg-blue-500/20 text-3xl text-white font-black">{idx + 1}</div>
              <span className="text-3xl text-slate-100 font-bold leading-snug">{opt}</span>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderSuccess = (icon, title, text, nextStage, isFinalStep = false) => (
    <div className="flex flex-col items-center justify-center h-full py-24 px-12 relative z-10">
      <HeaderLogo />
      <div className="absolute inset-0 bg-blue-600/10 animate-[pulse_4s_infinite] z-0"></div>
      <div className="z-10 flex flex-col items-center text-center mt-28">
        <div className="mb-16 p-12 bg-emerald-500/20 rounded-full ring-8 ring-emerald-500/50 shadow-[0_0_80px_rgba(16,185,129,0.5)]">
           {icon}
        </div>
        <h2 className="text-6xl font-black text-emerald-400 mb-12 uppercase tracking-widest leading-none">{title}</h2>
        <p className="text-4xl text-white leading-relaxed mb-24 max-w-3xl font-medium">{text}</p>
        <ActionButton onClick={() => setStage(nextStage)} variant="success">
          {isFinalStep ? "CONCLUIR MISSÃO" : "PRÓXIMO DESAFIO"} <ArrowRight className="ml-4" size={40} />
        </ActionButton>
      </div>
    </div>
  );

  const renderFinal = () => (
    <div className="flex flex-col items-center justify-between h-full py-32 px-12 text-center relative z-10">
      <HeaderLogo />
      <div className="mt-40 animate-bounce">
         <Star size={180} className="text-yellow-400 fill-yellow-400 drop-shadow-[0_0_60px_rgba(250,204,21,0.8)]" />
      </div>
      <div>
        <h1 className="text-7xl font-black text-white uppercase mb-12 tracking-tighter leading-none">Missão Cumprida!</h1>
        <div className="bg-white/10 backdrop-blur-xl p-16 rounded-[4rem] border-2 border-white/20 shadow-2xl">
          <p className="text-4xl text-slate-100 font-medium leading-tight mb-12">{outroText}</p>
          <div className="font-black text-blue-300 text-5xl uppercase tracking-[0.2em]">Escola em Órbita</div>
        </div>
      </div>
      <ActionButton onClick={() => setStage(13)} variant="primary">REGISTRAR MISSÃO</ActionButton>
    </div>
  );

  const renderCabin = () => (
    <div className="flex flex-col items-center justify-center h-full py-24 px-12 relative z-10 bg-indigo-950/60">
       <HeaderLogo />
       <div className="z-10 text-center mt-28">
         <h2 className="text-8xl font-black text-white mb-12 uppercase tracking-tighter leading-none">Cabine de Registro</h2>
         <p className="text-4xl text-slate-200 mb-20 leading-relaxed font-medium">Entre na cabine e oficialize a decolagem da sua escola para uma nova galáxia de desenvolvimento.</p>
         <div className="animate-pulse">
            <ActionButton onClick={() => window.location.reload()} variant="primary">DECOLAR AGORA</ActionButton>
         </div>
         <p className="mt-16 text-slate-400 text-2xl uppercase tracking-[0.5em] font-black">Sistema Pronto</p>
       </div>
    </div>
  );

  const renderStage = () => {
    switch(stage) {
      case 0: return renderIntro();
      case 1: return renderPilot();
      case 2: return renderLaunch();
      case 3: return renderAlert(<AlertTriangle size={180} className="text-red-500" />, "Atenção Comandante!", "Chuva de meteoros detectada! Também conhecidos como: Boletos e Inadimplência.", 4);
      case 4: return renderDecision("Para estabilizar a nave, qual decisão você toma?", ["Adiar o pagamento da tripulação", "Ignorar o problema e seguir rota", "Buscar solução que traga previsibilidade financeira"], 2, 5);
      case 5: return renderSuccess(<Shield size={180} className="text-emerald-400" />, "Escudos Ativados!", "Você conquistou previsibilidade financeira. Rota estabilizada.", 6);
      case 6: return renderAlert(<Wifi size={180} className="text-red-500 animate-pulse" />, "Perda de Sinal", "Sua escola está invisível para o universo. A comunicação falhou.", 7);
      case 7: return renderDecision("Como tornar sua escola visível na galáxia?", ["Esperar indicações passivamente", "Investir em posicionamento e marketing estratégico", "Reduzir comunicação para economizar"], 1, 8);
      case 8: return renderSuccess(<Wifi size={180} className="text-emerald-400" />, "Sinal Ativo", "Sua escola voltou para o radar. Matrículas em órbita!", 9);
      case 9: return renderAlert(<Battery size={180} className="text-red-500 rotate-90" />, "Combustível Baixo", "Sem investimento não há expansão. Você precisa de potência financeira.", 10);
      case 10: return renderDecision("Como garantir recursos para expandir com segurança?", ["Paralisar projetos atuais", "Buscar crédito estruturado para investir", "Aguardar sobras de caixa"], 1, 11);
      case 11: return renderSuccess(<Zap size={180} className="text-yellow-400 fill-yellow-400" />, "Impulso Máximo!", "Combustível reabastecido. Sua escola tem potência total agora.", 12, true);
      case 12: return renderFinal();
      case 13: return renderCabin();
      default: return renderIntro();
    }
  };

  return (
    <div className="w-full h-screen bg-neutral-950 flex items-center justify-center overflow-hidden">
      <div className="relative bg-black shadow-[0_0_100px_rgba(0,0,0,1)] w-full h-full max-w-[1080px] max-h-[1920px] aspect-[1080/1920] overflow-hidden">
        <SpaceBackground />
        <div className="relative z-10 w-full h-full flex flex-col">
          {renderStage()}
        </div>
        {showError && <ErrorOverlay onRetry={closeError} />}
      </div>
      <style>{`
        @keyframes slideUp {
          0% { transform: translateY(110%) scale(1.5); opacity: 0; }
          10% { opacity: 1; }
          100% { transform: translateY(-150vh) scale(0.5); }
        }
      `}</style>
    </div>
  );
}

