import React from 'react';

interface ActionButtonProps {
  onClick: () => void;
  children: React.ReactNode;
  variant?: 'primary' | 'alert' | 'success' | 'neutral';
  className?: string;
  disabled?: boolean;
}

export const ActionButton: React.FC<ActionButtonProps> = ({ 
  onClick, 
  children, 
  variant = 'primary', 
  className = '',
  disabled = false
}) => {
  const baseStyles = "w-full min-h-[140px] text-2xl font-black uppercase tracking-widest rounded-3xl transition-all duration-200 active:scale-95 flex items-center justify-center text-center px-10 shadow-xl relative overflow-hidden group disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-gradient-to-r from-blue-600 to-indigo-700 border-4 border-blue-400/30 text-white shadow-[0_0_40px_rgba(59,130,246,0.4)] hover:shadow-[0_0_60px_rgba(59,130,246,0.7)]",
    alert: "bg-gradient-to-r from-red-600 to-orange-700 border-4 border-red-400/30 text-white shadow-[0_0_40px_rgba(220,38,38,0.4)] animate-pulse",
    neutral: "bg-slate-800/80 backdrop-blur-md border-4 border-slate-600 text-slate-200 hover:bg-slate-700",
    success: "bg-gradient-to-r from-emerald-600 to-teal-700 border-4 border-emerald-400/30 text-white shadow-[0_0_40px_rgba(16,185,129,0.4)]",
  };

  return (
    <button 
      onClick={onClick} 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled}
    >
      <span className="relative z-10 flex items-center gap-4">{children}</span>
      <div className="absolute top-0 left-0 w-full h-1/2 bg-white/10 z-0"></div>
    </button>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  AlertTriangle, 
  Wifi, 
  Battery, 
  Zap, 
  User, 
  CheckCircle, 
  ArrowRight, 
  Star, 
  Loader2 
} from 'lucide-react';
import { SpaceBackground, HeaderLogo, RealisticRocket, LOGO_URL, PILOT_1_URL, PILOT_2_URL } from './components/Visuals';
import { ActionButton } from './components/Buttons';
import { fetchIntroText, fetchOutroText } from './services/geminiService';
import { PilotType } from './types';

const App: React.FC = () => {
  const [stage, setStage] = useState(0);
  const [pilot, setPilot] = useState<PilotType>(null);
  const [showError, setShowError] = useState(false);
  const [introText, setIntroText] = useState("Toda escola que cresce precisa enfrentar uma grande missão. Hoje, você assume o comando da sua!");
  const [outroText, setOutroText] = useState("Pilotar a gestão escolar não é simples. Mas com estabilidade e suporte, tudo fica mais leve.");
  const [loadingAI, setLoadingAI] = useState(false);

  // Initialize AI Content
  useEffect(() => {
    const initAI = async () => {
      setLoadingAI(true);
      const text = await fetchIntroText();
      setIntroText(text);
      setLoadingAI(false);
    };
    initAI();
  }, []);

  // Fetch Outro Content when reaching final stage
  useEffect(() => {
    if (stage === 12) {
      const getOutro = async () => {
        const text = await fetchOutroText();
        setOutroText(text);
      };
      getOutro();
    }
  }, [stage]);

  // Handle auto-progression from launch to first alert
  useEffect(() => {
    if (stage === 2) {
      const timer = setTimeout(() => setStage(3), 4000);
      return () => clearTimeout(timer);
    }
  }, [stage]);

  const handleStart = () => setStage(1);
  const handleSelectPilot = (p: 'male' | 'female') => {
    setPilot(p);
    setTimeout(() => setStage(2), 600);
  };
  const handleDecision = (isCorrect: boolean, nextStageId: number) => {
    if (isCorrect) {
      setStage(nextStageId);
    } else {
      setShowError(true);
    }
  };

  // Error Overlay Component
  const ErrorOverlay = () => (
    <div className="fixed inset-0 z-[100] bg-red-950/95 backdrop-blur-sm flex flex-col items-center justify-center p-12 animate-in fade-in zoom-in duration-300">
      <div className="bg-black/40 p-12 rounded-full mb-12 border-8 border-red-500 animate-bounce">
        <AlertTriangle size={120} className="text-red-500" />
      </div>
      <h2 className="text-6xl font-black text-white mb-8 text-center uppercase tracking-tighter drop-shadow-2xl">Impacto!</h2>
      <p className="text-2xl text-red-100 text-center mb-16 max-w-2xl leading-relaxed">
        Essa decisão pode comprometer o fluxo da missão. <br/>Ajuste a rota, comandante.
      </p>
      <ActionButton onClick={() => setShowError(false)} variant="primary" className="max-w-md">
        <Zap className="mr-4" /> Tentar Novamente
      </ActionButton>
    </div>
  );

  // Screen Renders
  const renderIntro = () => (
    <div className="flex flex-col items-center justify-between h-full py-20 px-12 text-center relative z-10">
      <div className="mt-12 w-full flex flex-col items-center">
        <div className="p-4 mb-10 animate-in zoom-in duration-1000 w-full flex justify-center overflow-visible">
          <img 
            src={LOGO_URL} 
            alt="Kedu Logo" 
            className="max-w-[75%] h-auto object-contain drop-shadow-[0_0_50px_rgba(59,130,246,0.3)]"
          />
        </div>
        <h1 className="text-6xl md:text-8xl font-black text-white uppercase tracking-tighter mb-4 drop-shadow-[0_0_20px_rgba(255,255,255,0.3)] leading-none">
          Base Espacial<br/><span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">KEDU</span>
        </h1>
      </div>

      <div className="bg-slate-900/70 backdrop-blur-md p-10 rounded-[3rem] border-2 border-slate-700 shadow-2xl min-h-[300px] flex items-center justify-center w-full max-w-4xl">
        {loadingAI ? <Loader2 className="animate-spin text-blue-400" size={60} /> : (
          <p className="text-3xl text-slate-100 font-medium leading-tight animate-in fade-in duration-700">{introText}</p>
        )}
      </div>

      <div className="w-full max-w-md">
        <ActionButton onClick={handleStart} variant="primary">INICIAR MISSÃO</ActionButton>
      </div>
    </div>
  );

  const renderPilotSelection = () => (
    <div className="flex flex-col items-center h-full py-20 px-12 relative z-10">
      <HeaderLogo />
      <h2 className="text-5xl font-black text-white text-center mb-4 mt-32 uppercase tracking-widest">Escolha o Piloto</h2>
      <p className="text-2xl text-slate-300 text-center mb-12 font-medium">Quem representa você nessa jornada?</p>
      <div className="flex-1 w-full flex flex-col gap-8 justify-center max-w-4xl">
        {['male', 'female'].map((p) => (
          <button 
            key={p} 
            onClick={() => handleSelectPilot(p as 'male' | 'female')}
            className={`relative rounded-[2.5rem] border-4 transition-all duration-300 flex items-center gap-8 p-8 min-h-[220px]
              ${pilot === p ? 'bg-blue-900/80 border-blue-400 shadow-[0_0_60px_rgba(59,130,246,0.6)] scale-105 z-20' : 'bg-slate-800/40 border-slate-700 opacity-80'}`}
          >
            <div className="w-32 h-32 rounded-full overflow-hidden border-2 border-blue-400/30 bg-slate-700 shadow-xl flex-shrink-0">
              <img 
                src={p === 'male' ? PILOT_1_URL : PILOT_2_URL} 
                alt="Comandante" 
                className="w-full h-full object-cover"
                onError={(e) => { (e.target as HTMLImageElement).style.display = 'none'; }}
              />
              <div className="w-full h-full flex items-center justify-center bg-slate-800">
                <User size={60} className="text-white opacity-20" />
              </div>
            </div>
            <div className="text-left">
              <span className="text-3xl md:text-4xl font-black text-white uppercase tracking-wider">{p === 'male' ? 'Comandante Alpha' : 'Comandante Beta'}</span>
              <p className="text-blue-300 font-bold uppercase text-sm mt-1">Status: Pronto para Decolagem</p>
            </div>
            {pilot === p && <div className="ml-auto bg-blue-500 rounded-full p-2 animate-bounce"><CheckCircle className="text-white" size={32} /></div>}
          </button>
        ))}
      </div>
    </div>
  );

  const renderLaunch = () => (
    <div className="flex flex-col items-center justify-center h-full relative z-10 overflow-hidden">
      <HeaderLogo />
      <div className="absolute inset-0 flex items-end justify-center pb-40 animate-rocket-launch">
        <div className="relative flex flex-col items-center">
          <div className="absolute top-[80%] w-32 h-[800px] bg-gradient-to-b from-orange-400 via-orange-600/50 to-transparent blur-[60px] animate-pulse"></div>
          <RealisticRocket size={300} className="drop-shadow-[0_0_50px_rgba(255,255,255,0.4)]" />
        </div>
      </div>
      <div className="absolute top-[30%] w-full text-center px-12 z-20">
        <h2 className="text-6xl font-black text-white mb-6 animate-pulse uppercase tracking-widest drop-shadow-2xl">Decolagem Autorizada</h2>
        <p className="text-3xl text-blue-200 uppercase font-bold tracking-tighter opacity-80">Iniciando protocolo de crescimento...</p>
      </div>
    </div>
  );

  const renderAlert = (icon: React.ReactNode, title: string, text: string, next: number) => (
    <div className="flex flex-col items-center justify-center h-full py-20 px-12 relative z-10">
      <HeaderLogo />
      <div className="absolute inset-0 bg-red-600/5 animate-pulse z-0"></div>
      <div className="z-10 flex flex-col items-center text-center mt-24 w-full max-w-4xl">
        <div className="mb-10 relative">
           <div className="absolute inset-0 bg-red-500 blur-[80px] opacity-40 animate-ping"></div>
           {icon}
        </div>
        <h2 className="text-6xl font-black text-red-500 mb-8 uppercase tracking-tighter leading-none">{title}</h2>
        <div className="bg-slate-900/90 border-4 border-red-500/50 p-12 rounded-[2.5rem] mb-12 shadow-2xl">
          <p className="text-2xl text-white leading-tight font-medium">{text}</p>
        </div>
        <div className="w-full max-w-md">
          <ActionButton onClick={() => setStage(next)} variant="alert">ACESSAR PAINEL</ActionButton>
        </div>
      </div>
    </div>
  );

  const renderDecision = (question: string, options: string[], correctIndex: number, next: number) => (
    <div className="flex flex-col h-full py-20 px-12 relative z-10">
      <HeaderLogo />
      <div className="mt-32 mb-10">
        <h2 className="text-3xl font-black text-blue-400 uppercase mb-2 tracking-widest">Painel de Controle</h2>
        <div className="h-2 w-32 bg-blue-500 rounded-full shadow-[0_0_20px_rgba(59,130,246,0.8)]"></div>
      </div>
      <div className="mb-10">
        <h3 className="text-4xl font-black text-white leading-tight drop-shadow-md">{question}</h3>
      </div>
      <div className="flex-1 flex flex-col gap-6 justify-center w-full max-w-4xl mx-auto">
        {options.map((opt, idx) => (
          <button 
            key={idx} 
            onClick={() => handleDecision(idx === correctIndex, next)}
            className="w-full p-8 min-h-[160px] rounded-[2rem] bg-slate-800/80 border-4 border-slate-600 hover:border-blue-400 text-left transition-all active:scale-95 group relative overflow-hidden"
          >
            <div className="flex items-start gap-6 relative z-10">
              <div className="mt-1 w-12 h-12 rounded-full border-4 border-slate-500 flex-shrink-0 flex items-center justify-center group-hover:border-blue-400 group-hover:bg-blue-500/20 text-2xl text-white font-black">{idx + 1}</div>
              <span className="text-2xl text-slate-100 font-bold leading-snug">{opt}</span>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderSuccess = (icon: React.ReactNode, title: string, text: string, next: number, isFinal = false) => (
    <div className="flex flex-col items-center justify-center h-full py-20 px-12 relative z-10">
      <HeaderLogo />
      <div className="absolute inset-0 bg-emerald-600/5 animate-pulse z-0"></div>
      <div className="z-10 flex flex-col items-center text-center mt-24 w-full max-w-4xl">
        <div className="mb-10 p-10 bg-emerald-500/20 rounded-full ring-8 ring-emerald-500/30 shadow-[0_0_60px_rgba(16,185,129,0.3)]">
           {icon}
