        <h2 className="text-5xl font-black text-emerald-400 mb-8 uppercase tracking-widest leading-none">{title}</h2>
        <p className="text-2xl text-white leading-relaxed mb-16 max-w-3xl font-medium">{text}</p>
        <div className="w-full max-w-md">
          <ActionButton onClick={() => setStage(next)} variant="success">
            {isFinal ? "CONCLUIR MISSÃO" : "PRÓXIMO DESAFIO"} <ArrowRight className="ml-4" size={32} />
