  );

  const renderFinal = () => (
    <div className="flex flex-col items-center justify-between h-full py-24 px-12 text-center relative z-10">
      <HeaderLogo />
      <div className="mt-32 animate-bounce">
         <Star size={140} className="text-yellow-400 fill-yellow-400 drop-shadow-[0_0_60px_rgba(250,204,21,0.6)]" />
      </div>
      <div className="w-full max-w-4xl">
        <h1 className="text-6xl font-black text-white uppercase mb-8 tracking-tighter leading-none">Missão Cumprida!</h1>
        <div className="bg-white/10 backdrop-blur-xl p-12 rounded-[3rem] border-2 border-white/20 shadow-2xl">
          <p className="text-2xl text-slate-100 font-medium leading-tight mb-8 italic">"{outroText}"</p>
          <div className="font-black text-blue-300 text-4xl uppercase tracking-[0.2em]">Escola em Órbita</div>
        </div>
      </div>
      <div className="w-full max-w-md">
        <ActionButton onClick={() => setStage(13)} variant="primary">REGISTRAR SUCESSO</ActionButton>
      </div>
    </div>
  );

  const renderCabin = () => (
    <div className="flex flex-col items-center justify-center h-full py-24 px-12 relative z-10 bg-indigo-950/60">
       <HeaderLogo />
       <div className="z-10 text-center mt-24 w-full max-w-4xl">
         <h2 className="text-7xl font-black text-white mb-8 uppercase tracking-tighter leading-none">Cabine de Comando</h2>
