  );

  const renderCurrentStage = () => {
    switch(stage) {
      case 0: return renderIntro();
      case 1: return renderPilotSelection();
      case 2: return renderLaunch();
      case 3: return renderAlert(<AlertTriangle size={140} className="text-red-500" />, "Atenção Comandante!", "Chuva de meteoros detectada! Também conhecidos como: Boletos e Inadimplência.", 4);
      case 4: return renderDecision(
        "Para estabilizar a nave, qual decisão você toma?", 
        ["Adiar o pagamento da tripulação", "Ignorar o problema e seguir rota", "Buscar solução que traga previsibilidade financeira"], 
        2, 5
      );
      case 5: return renderSuccess(<Shield size={140} className="text-emerald-400" />, "Escudos Ativados!", "Você conquistou previsibilidade financeira. Rota estabilizada com KEDU.", 6);
      case 6: return renderAlert(<Wifi size={140} className="text-red-500 animate-pulse" />, "Perda de Sinal", "Sua escola está invisível para o universo. A comunicação com pais e alunos falhou.", 7);
      case 7: return renderDecision(
        "Como tornar sua escola visível na galáxia?", 
        ["Esperar indicações passivamente", "Investir em posicionamento e marketing estratégico", "Reduzir comunicação para economizar"], 
        1, 8
      );
      case 8: return renderSuccess(<Wifi size={140} className="text-emerald-400" />, "Sinal Ativo", "Sua escola voltou para o radar. Captação de matrículas em órbita!", 9);
      case 9: return renderAlert(<Battery size={140} className="text-red-500 rotate-90" />, "Combustível Baixo", "Sem investimento não há expansão. Você precisa de potência financeira para crescer.", 10);
      case 10: return renderDecision(
        "Como garantir recursos para expandir com segurança?", 
        ["Paralisar projetos atuais", "Buscar crédito estruturado para investir", "Aguardar sobras de caixa"], 
        1, 11
      );
      case 11: return renderSuccess(<Zap size={140} className="text-yellow-400 fill-yellow-400" />, "Impulso Máximo!", "Combustível reabastecido. Sua escola tem potência total para dominar o setor.", 12, true);
      case 12: return renderFinal();
      case 13: return renderCabin();
      default: return renderIntro();
    }
  };

  return (
    <div className="w-full h-screen bg-neutral-950 flex items-center justify-center overflow-hidden font-sans">
      {/* Mobile-focused container (1080x1920 aspect ratio simulation) */}
      <div className="relative bg-black shadow-[0_0_100px_rgba(0,0,0,1)] w-full h-full max-w-[500px] md:max-w-[600px] lg:max-w-[800px] overflow-hidden border-x border-slate-800">
        <SpaceBackground />
        <div className="relative z-10 w-full h-full flex flex-col">
          {renderCurrentStage()}
        </div>
        {showError && <ErrorOverlay />}
      </div>
    </div>
  );
};

