import React from 'react';

export type PilotType = 'male' | 'female' | null;

export interface GameState {
  stage: number;
  pilot: PilotType;
  showError: boolean;
  introText: string;
  outroText: string;
  isLoadingAI: boolean;
}

export interface DecisionOption {
