  Zap, 
  User, 
  CheckCircle, 
  ArrowRight, 
  Star, 
  Loader2 
} from 'lucide-react';
import { SpaceBackground, HeaderLogo, RealisticRocket, LOGO_URL, PILOT_1_URL, PILOT_2_URL } from './components/Visuals';
import { ActionButton } from './components/Buttons';
import { fetchIntroText, fetchOutroText } from './services/geminiService';
import { PilotType } from './types';

const App: React.FC = () => {
  const [stage, setStage] = useState(0);
  const [pilot, setPilot] = useState<PilotType>(null);
  const [showError, setShowError] = useState(false);
  const [introText, setIntroText] = useState("Toda escola que cresce precisa enfrentar uma grande missão. Hoje, você assume o comando da sua!");
  const [outroText, setOutroText] = useState("Pilotar a gestão escolar não é simples. Mas com estabilidade e suporte, tudo fica mais leve.");
  const [loadingAI, setLoadingAI] = useState(false);

  useEffect(() => {
    const initAI = async () => {
      setLoadingAI(true);
      const text = await fetchIntroText();
      setIntroText(text);
      setLoadingAI(false);
    };
    initAI();
  }, []);

  useEffect(() => {
    if (stage === 12) {
      const getOutro = async () => {
        const text = await fetchOutroText();
        setOutroText(text);
      };
      getOutro();
    }
  }, [stage]);

  useEffect(() => {
    if (stage === 2) {
      const timer = setTimeout(() => setStage(3), 4000);
      return () => clearTimeout(timer);
    }
  }, [stage]);

  const handleStart = () => setStage(1);
  const handleSelectPilot = (p: 'male' | 'female') => {
    setPilot(p);
    setTimeout(() => setStage(2), 600);
  };
  const handleDecision = (isCorrect: boolean, nextStageId: number) => {
    if (isCorrect) {
      setStage(nextStageId);
    } else {
      setShowError(true);
    }
  };

  const ErrorOverlay = () => (
    <div className="fixed inset-0 z-[100] bg-red-950/98 backdrop-blur-md flex flex-col items-center justify-center p-6 animate-in fade-in zoom-in duration-300">
      <div className="bg-black/40 p-8 rounded-full mb-6 border-4 border-red-500 animate-bounce">
        <AlertTriangle size={80} className="text-red-500" />
      </div>
      <h2 className="text-4xl md:text-6xl font-black text-white mb-4 text-center uppercase tracking-tighter drop-shadow-2xl">Impacto!</h2>
      <p className="text-lg md:text-2xl text-red-100 text-center mb-10 max-w-md leading-relaxed">
        Essa decisão pode comprometer o fluxo da missão. <br/>Ajuste a rota, comandante.
      </p>
      <div className="w-full max-w-xs">
        <ActionButton onClick={() => setShowError(false)} variant="primary" className="min-h-[80px]">
          <Zap className="mr-2" size={24} /> Tentar Novamente
        </ActionButton>
      </div>
    </div>
  );

  const renderIntro = () => (
    <div className="flex flex-col items-center justify-between h-full py-8 md:py-16 px-6 text-center relative z-10 overflow-y-auto">
      <div className="w-full flex flex-col items-center gap-6">
        <div className="animate-in zoom-in duration-1000 w-full flex justify-center">
          <img 
            src={LOGO_URL} 
            alt="Kedu Logo" 
            className="max-w-[180px] md:max-w-[280px] h-auto object-contain drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]"
          />
        </div>
        <h1 className="text-4xl md:text-7xl font-black text-white uppercase tracking-tighter drop-shadow-[0_0_20px_rgba(255,255,255,0.3)] leading-none">
          Base Espacial<br/><span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">KEDU</span>
        </h1>
      </div>

      <div className="bg-slate-900/70 backdrop-blur-md p-6 md:p-10 rounded-[2rem] border-2 border-slate-700 shadow-2xl my-8 w-full max-w-lg">
        {loadingAI ? (
          <div className="flex justify-center p-8"><Loader2 className="animate-spin text-blue-400" size={40} /></div>
        ) : (
          <p className="text-xl md:text-3xl text-slate-100 font-medium leading-tight animate-in fade-in duration-700">{introText}</p>
        )}
      </div>

      <div className="w-full max-w-xs">
        <ActionButton onClick={handleStart} variant="primary" className="min-h-[80px]">INICIAR MISSÃO</ActionButton>
      </div>
    </div>
  );

  const renderPilotSelection = () => (
    <div className="flex flex-col items-center h-full py-8 px-6 relative z-10 overflow-y-auto">
      <HeaderLogo />
      <div className="mt-24 mb-6 text-center">
        <h2 className="text-3xl md:text-5xl font-black text-white uppercase tracking-widest">O Piloto</h2>
        <p className="text-lg md:text-2xl text-slate-300 font-medium">Quem assume o comando?</p>
      </div>
      <div className="flex-1 w-full flex flex-col gap-4 justify-center max-w-lg">
        {['male', 'female'].map((p) => (
          <button 
            key={p} 
            onClick={() => handleSelectPilot(p as 'male' | 'female')}
            className={`relative rounded-[1.5rem] border-2 transition-all duration-300 flex items-center gap-4 p-4 md:p-6
              ${pilot === p ? 'bg-blue-900/80 border-blue-400 shadow-[0_0_30px_rgba(59,130,246,0.4)] scale-[1.02]' : 'bg-slate-800/40 border-slate-700 opacity-80'}`}
          >
            <div className="w-20 h-20 md:w-24 md:h-24 rounded-full overflow-hidden border-2 border-blue-400/30 bg-slate-700 flex-shrink-0">
              <img 
                src={p === 'male' ? PILOT_1_URL : PILOT_2_URL} 
                alt="Comandante" 
                className="w-full h-full object-cover"
              />
            </div>
            <div className="text-left flex-1">
              <span className="text-xl md:text-2xl font-black text-white uppercase tracking-wider">{p === 'male' ? 'Cmdt. Alpha' : 'Cmdt. Beta'}</span>
              <p className="text-blue-300 font-bold uppercase text-xs">Status: Pronto</p>
            </div>
            {pilot === p && <CheckCircle className="text-blue-400" size={28} />}
          </button>
        ))}
      </div>
    </div>
  );

  const renderLaunch = () => (
    <div className="flex flex-col items-center justify-center h-full relative z-10 overflow-hidden px-6">
      <HeaderLogo />
      <div className="absolute inset-0 flex items-end justify-center pb-20 animate-rocket-launch">
        <div className="relative flex flex-col items-center">
          <RealisticRocket size={200} className="drop-shadow-[0_0_50px_rgba(255,255,255,0.4)]" />
        </div>
      </div>
      <div className="relative z-20 text-center mt-[-20%]">
        <h2 className="text-4xl md:text-6xl font-black text-white mb-4 animate-pulse uppercase tracking-widest">Decolando</h2>
        <p className="text-xl text-blue-200 uppercase font-bold tracking-tighter opacity-80">Protocolo Ativo...</p>
      </div>
    </div>
  );

  const renderAlert = (icon: React.ReactNode, title: string, text: string, next: number) => (
    <div className="flex flex-col items-center justify-center h-full py-8 px-6 relative z-10 overflow-y-auto">
      <HeaderLogo />
      <div className="z-10 flex flex-col items-center text-center mt-20 w-full max-w-lg">
        <div className="mb-6 relative">
           <div className="absolute inset-0 bg-red-500 blur-[40px] opacity-30 animate-ping"></div>
           {React.cloneElement(icon as React.ReactElement, { size: 80 })}
        </div>
        <h2 className="text-3xl md:text-5xl font-black text-red-500 mb-6 uppercase tracking-tighter leading-none">{title}</h2>
        <div className="bg-slate-900/90 border-2 border-red-500/50 p-6 md:p-8 rounded-[1.5rem] mb-8 shadow-2xl">
          <p className="text-lg md:text-2xl text-white leading-tight font-medium">{text}</p>
        </div>
        <div className="w-full max-w-xs">
          <ActionButton onClick={() => setStage(next)} variant="alert" className="min-h-[80px]">ACESSAR PAINEL</ActionButton>
        </div>
      </div>
    </div>
  );

  const renderDecision = (question: string, options: string[], correctIndex: number, next: number) => (
    <div className="flex flex-col h-full py-8 px-6 relative z-10 overflow-y-auto">
      <HeaderLogo />
      <div className="mt-20 mb-6">
        <h2 className="text-xl font-black text-blue-400 uppercase tracking-widest">Controle</h2>
        <div className="h-1.5 w-16 bg-blue-500 rounded-full"></div>
      </div>
      <div className="mb-8">
        <h3 className="text-2xl md:text-4xl font-black text-white leading-tight">{question}</h3>
      </div>
      <div className="flex flex-col gap-4 w-full max-w-lg mx-auto pb-8">
        {options.map((opt, idx) => (
          <button 
            key={idx} 
            onClick={() => handleDecision(idx === correctIndex, next)}
            className="w-full p-5 md:p-6 rounded-[1.5rem] bg-slate-800/80 border-2 border-slate-600 hover:border-blue-400 text-left transition-all active:scale-95 group"
          >
            <div className="flex items-start gap-4">
              <div className="mt-0.5 w-8 h-8 rounded-full border-2 border-slate-500 flex-shrink-0 flex items-center justify-center text-sm text-white font-black group-hover:bg-blue-500/20">{idx + 1}</div>
              <span className="text-lg md:text-xl text-slate-100 font-bold leading-snug">{opt}</span>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderSuccess = (icon: React.ReactNode, title: string, text: string, next: number, isFinal = false) => (
    <div className="flex flex-col items-center justify-center h-full py-8 px-6 relative z-10 overflow-y-auto">
      <HeaderLogo />
      <div className="z-10 flex flex-col items-center text-center mt-20 w-full max-w-lg">
        <div className="mb-6 p-6 bg-emerald-500/20 rounded-full shadow-xl">
           {React.cloneElement(icon as React.ReactElement, { size: 80 })}
        </div>
        <h2 className="text-3xl md:text-5xl font-black text-emerald-400 mb-6 uppercase tracking-widest leading-none">{title}</h2>
        <p className="text-lg md:text-2xl text-white leading-relaxed mb-10 font-medium">{text}</p>
        <div className="w-full max-w-xs">
          <ActionButton onClick={() => setStage(next)} variant="success" className="min-h-[80px]">
            {isFinal ? "CONCLUIR" : "PRÓXIMO"} <ArrowRight className="ml-2" size={24} />
          </ActionButton>
        </div>
      </div>
    </div>
  );

  const renderFinal = () => (
    <div className="flex flex-col items-center justify-between h-full py-12 px-6 text-center relative z-10 overflow-y-auto">
      <HeaderLogo />
      <div className="mt-20 mb-6 animate-bounce">
         <Star size={100} className="text-yellow-400 fill-yellow-400 drop-shadow-[0_0_40px_rgba(250,204,21,0.5)]" />
      </div>
      <div className="w-full max-w-lg">
        <h1 className="text-4xl md:text-6xl font-black text-white uppercase mb-6 tracking-tighter leading-none">Missão Cumprida!</h1>
        <div className="bg-white/10 backdrop-blur-md p-6 md:p-10 rounded-[2rem] border-2 border-white/20 shadow-2xl mb-8">
          <p className="text-lg md:text-2xl text-slate-100 font-medium leading-tight mb-6 italic">"{outroText}"</p>
          <div className="font-black text-blue-300 text-2xl md:text-3xl uppercase tracking-widest">Escola em Órbita</div>
        </div>
      </div>
      <div className="w-full max-w-xs">
        <ActionButton onClick={() => setStage(13)} variant="primary" className="min-h-[80px]">FINALIZAR</ActionButton>
      </div>
    </div>
  );

  const renderCabin = () => (
    <div className="flex flex-col items-center justify-center h-full py-12 px-6 relative z-10 overflow-y-auto bg-indigo-950/40">
       <HeaderLogo />
       <div className="z-10 text-center mt-20 w-full max-w-lg">
         <h2 className="text-4xl md:text-6xl font-black text-white mb-6 uppercase tracking-tighter">Cabine</h2>
         <p className="text-lg md:text-2xl text-slate-200 mb-12 leading-relaxed">Sua escola agora brilha em uma nova galáxia de resultados.</p>
         <div className="w-full max-w-xs mx-auto">
            <ActionButton onClick={() => window.location.reload()} variant="primary" className="min-h-[80px]">NOVA MISSÃO</ActionButton>
         </div>
       </div>
    </div>
  );

  const renderCurrentStage = () => {
    switch(stage) {
      case 0: return renderIntro();
      case 1: return renderPilotSelection();
      case 2: return renderLaunch();
      case 3: return renderAlert(<AlertTriangle className="text-red-500" />, "Atenção!", "Chuva de meteoros detectada: Inadimplência à vista!", 4);
      case 4: return renderDecision(
        "Como estabilizar a nave agora?", 
        ["Adiar pagamentos da equipe", "Ignorar e seguir rota", "Usar KEDU para previsibilidade financeira"], 
        2, 5
      );
      case 5: return renderSuccess(<Shield className="text-emerald-400" />, "Escudos OK!", "Você conquistou previsibilidade financeira total.", 6);
      case 6: return renderAlert(<Wifi className="text-red-500 animate-pulse" />, "Sem Sinal", "A comunicação com pais e alunos falhou no hiperespaço.", 7);
      case 7: return renderDecision(
        "Como retomar a visibilidade?", 
        ["Esperar indicações", "Marketing estratégico e posicionamento", "Reduzir custos de marketing"], 
        1, 8
      );
      case 8: return renderSuccess(<Wifi className="text-emerald-400" />, "Sinal Forte", "Captação de matrículas atingiu velocidade da luz!", 9);
      case 9: return renderAlert(<Battery className="text-red-500 rotate-90" />, "Baixa Energia", "Sem investimento, a expansão da escola está paralisada.", 10);
      case 10: return renderDecision(
        "Como obter potência para crescer?", 
        ["Parar projetos", "Crédito estruturado para investir", "Esperar sobra de caixa"], 
        1, 11
      );
      case 11: return renderSuccess(<Zap className="text-yellow-400 fill-yellow-400" />, "Impulso!", "Combustível reabastecido. Potência total para dominar o setor!", 12, true);
      case 12: return renderFinal();
      case 13: return renderCabin();
      default: return renderIntro();
    }
  };

  return (
    <div className="w-full h-[100dvh] bg-black flex items-center justify-center overflow-hidden font-sans">
      {/* Dynamic responsive container */}
      <div className="relative w-full h-full max-w-2xl bg-slate-950 overflow-hidden shadow-2xl">
        <SpaceBackground />
        <div className="relative z-10 w-full h-full">
          {renderCurrentStage()}
        </div>
        {showError && <ErrorOverlay />}
      </div>
    </div>
  );
};

export default App;

import React from 'react';

interface ActionButtonProps {
  onClick: () => void;
  children: React.ReactNode;
  variant?: 'primary' | 'alert' | 'success' | 'neutral';
  className?: string;
  disabled?: boolean;
}

export const ActionButton: React.FC<ActionButtonProps> = ({ 
  onClick, 
  children, 
  variant = 'primary', 
  className = '',
  disabled = false
}) => {
  const baseStyles = "w-full min-h-[70px] md:min-h-[100px] text-xl md:text-2xl font-black uppercase tracking-widest rounded-2xl md:rounded-3xl transition-all duration-200 active:scale-95 flex items-center justify-center text-center px-6 md:px-10 shadow-xl relative overflow-hidden group disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-gradient-to-r from-blue-600 to-indigo-700 border-2 md:border-4 border-blue-400/30 text-white shadow-[0_0_20px_rgba(59,130,246,0.3)] hover:shadow-[0_0_40px_rgba(59,130,246,0.5)]",
    alert: "bg-gradient-to-r from-red-600 to-orange-700 border-2 md:border-4 border-red-400/30 text-white shadow-[0_0_20px_rgba(220,38,38,0.3)]",
    neutral: "bg-slate-800/80 backdrop-blur-md border-2 md:border-4 border-slate-600 text-slate-200 hover:bg-slate-700",
    success: "bg-gradient-to-r from-emerald-600 to-teal-700 border-2 md:border-4 border-emerald-400/30 text-white shadow-[0_0_20px_rgba(16,185,129,0.3)]",
  };

  return (
    <button 
      onClick={onClick} 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled}
    >
      <span className="relative z-10 flex items-center gap-2 md:gap-4">{children}</span>
      <div className="absolute top-0 left-0 w-full h-1/2 bg-white/10 z-0"></div>
    </button>
  );
};
